head.b:skin:
/* ===================== CSS VARIABLES ===================== */
:root {
  --neon: #00ff9d;
  --neon2: #00cfff;
  --red: #ff2d55;
  --bg: #020c0e;
  --bg2: #040f12;
  --bg3: #071519;
  --card: #0a1e22;
  --card-hover: #0d2428;
  --border: rgba(0,255,157,0.18);
  --border-h: rgba(0,255,157,0.45);
  --text: #b0d4d8;
  --text-dim: rgba(176,212,216,0.55);
  --white: #e8f4f6;
  --glow: 0 0 20px rgba(0,255,157,0.4);
  --glow2: 0 0 20px rgba(0,207,255,0.3);
  --transition: all 0.35s cubic-bezier(0.4,0,0.2,1);
}
[data-theme="light"] {
  --bg: #f0f4f5;
  --bg2: #e4ecee;
  --bg3: #d8e6ea;
  --card: #ffffff;
  --card-hover: #f8fffe;
  --border: rgba(0,150,100,0.2);
  --border-h: rgba(0,150,100,0.5);
  --text: #1a3a3e;
  --text-dim: rgba(26,58,62,0.6);
  --white: #0d1f22;
  --neon: #007a4d;
  --neon2: #006699;
  --glow: 0 0 20px rgba(0,122,77,0.25);
  --glow2: 0 0 20px rgba(0,102,153,0.2);
}
* { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; }
body {
  background: var(--bg);
  color: var(--text);
  font-family: 'Rajdhani', 'Noto Sans Bengali', sans-serif;
  font-size: 16px;
  overflow-x: hidden;
  transition: background 0.4s, color 0.4s;
}
[dir="rtl"] body { font-family: 'Rajdhani', 'Noto Sans Arabic', sans-serif; }

/* ===================== PAGE TRANSITION ===================== */
#page-transition { position:fixed;inset:0;z-index:99999;pointer-events:none;display:flex;flex-direction:column; }
.pt-panel { flex:1;background:#000;transform:scaleY(0);transform-origin:top; }
.pt-panel:nth-child(2){transform-origin:bottom;transition-delay:0.05s;}
.pt-panel:nth-child(3){transform-origin:top;transition-delay:0.1s;}
.pt-panel{transition:transform 0.5s cubic-bezier(0.77,0,0.18,1);}
body.transitioning .pt-panel{transform:scaleY(1);}

/* ===================== LOADING SCREEN ===================== */
#loader {
  position:fixed;inset:0;background:#000;z-index:99998;
  display:flex;flex-direction:column;align-items:center;justify-content:center;
  font-family:'Share Tech Mono',monospace;transition:opacity 0.6s,visibility 0.6s;
}
#loader.hidden{opacity:0;visibility:hidden;}
.loader-logo {
  font-family:'Orbitron',monospace;font-size:clamp(1.5rem,4vw,2.5rem);font-weight:900;
  color:#00ff9d;text-shadow:0 0 30px rgba(0,255,157,0.8);margin-bottom:40px;
  letter-spacing:4px;animation:pulse-glow 1.5s ease-in-out infinite;
}
.loader-logo span{color:#ff2d55;}
@keyframes pulse-glow{
  0%,100%{text-shadow:0 0 20px rgba(0,255,157,0.6);}
  50%{text-shadow:0 0 50px rgba(0,255,157,1),0 0 80px rgba(0,255,157,0.4);}
}
.loader-terminal{width:min(500px,90vw);background:#050e10;border:1px solid rgba(0,255,157,0.3);border-radius:6px;overflow:hidden;}
.loader-terminal-bar{padding:8px 14px;background:#0a1a1e;display:flex;align-items:center;gap:7px;border-bottom:1px solid rgba(0,255,157,0.15);}
.ld{width:10px;height:10px;border-radius:50%;}
.ld.r{background:#ff2d55;}.ld.y{background:#ffd60a;}.ld.g{background:#30d158;}
.loader-terminal-title{font-size:0.65rem;color:rgba(0,255,157,0.4);letter-spacing:2px;margin-left:8px;}
.loader-terminal-body{padding:18px 20px;min-height:180px;}
.loader-line{font-size:0.78rem;line-height:1.9;color:rgba(176,212,216,0.8);display:none;}
.loader-line.show{display:block;}
.loader-line .ok{color:#00ff9d;}.loader-line .err{color:#ff2d55;}.loader-line .cmd{color:#00cfff;}.loader-line .warn{color:#ffd60a;}
.loader-bar-wrap{margin:18px 20px 16px;height:3px;background:rgba(0,255,157,0.1);border-radius:2px;overflow:hidden;}
.loader-bar{height:100%;background:linear-gradient(90deg,#00ff9d,#00cfff);box-shadow:0 0 10px rgba(0,255,157,0.6);width:0%;transition:width 0.3s ease;}
.loader-pct{text-align:right;padding:0 20px 16px;font-size:0.7rem;color:rgba(0,255,157,0.6);}

/* ===================== SCANLINES ===================== */
body::after {
  content:'';position:fixed;inset:0;
  background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.04) 2px,rgba(0,0,0,0.04) 4px);
  pointer-events:none;z-index:9998;opacity:0.6;
}
[data-theme="light"] body::after{display:none;}

/* ===================== NETWORK CANVAS ===================== */
#net-canvas{position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;opacity:0.55;transition:opacity 0.4s;}
[data-theme="light"] #net-canvas{opacity:0.2;}

/* ===================== NAV ===================== */
nav {
  position:fixed;top:0;width:100%;z-index:1000;padding:0 5%;height:62px;
  display:flex;justify-content:space-between;align-items:center;
  background:rgba(2,12,14,0.88);backdrop-filter:blur(14px);
  border-bottom:1px solid var(--border);transition:background 0.4s,border-color 0.4s;
}
[data-theme="light"] nav{background:rgba(240,244,245,0.92);}
.nav-logo{font-family:'Orbitron',monospace;font-size:1rem;font-weight:900;color:var(--neon);text-shadow:var(--glow);letter-spacing:2px;text-decoration:none;flex-shrink:0;}
.nav-logo span{color:var(--red);}
.nav-center{display:flex;gap:2rem;position:absolute;left:50%;transform:translateX(-50%);}
.nav-center a{font-family:'Share Tech Mono',monospace;font-size:0.72rem;color:var(--text-dim);text-decoration:none;letter-spacing:2px;text-transform:uppercase;transition:var(--transition);white-space:nowrap;}
.nav-center a:hover{color:var(--neon);}
.nav-right{display:flex;align-items:center;gap:12px;}

/* Language Selector */
.lang-select-wrap{position:relative;}
.lang-btn{display:flex;align-items:center;gap:6px;padding:6px 12px;background:var(--card);border:1px solid var(--border);color:var(--text);font-family:'Share Tech Mono',monospace;font-size:0.7rem;letter-spacing:1px;cursor:pointer;border-radius:3px;transition:var(--transition);}
.lang-btn:hover{border-color:var(--neon);color:var(--neon);}
.lang-btn .arrow{font-size:0.55rem;transition:transform 0.3s;}
.lang-select-wrap.open .arrow{transform:rotate(180deg);}
.lang-dropdown{position:absolute;top:calc(100% + 8px);right:0;background:var(--card);border:1px solid var(--border);border-radius:4px;overflow:hidden;min-width:160px;opacity:0;visibility:hidden;transform:translateY(-8px);transition:var(--transition);z-index:200;box-shadow:0 10px 30px rgba(0,0,0,0.4);}
.lang-select-wrap.open .lang-dropdown{opacity:1;visibility:visible;transform:translateY(0);}
.lang-option{display:flex;align-items:center;gap:10px;padding:10px 16px;font-family:'Share Tech Mono',monospace;font-size:0.7rem;color:var(--text);cursor:pointer;transition:background 0.2s;letter-spacing:1px;}
.lang-option:hover{background:rgba(0,255,157,0.07);color:var(--neon);}
.lang-option.active{color:var(--neon);background:rgba(0,255,157,0.05);}
.lang-flag{font-size:1rem;}

/* Theme Toggle */
.theme-toggle{width:38px;height:38px;border:1px solid var(--border);background:var(--card);color:var(--text);cursor:pointer;border-radius:3px;display:flex;align-items:center;justify-content:center;font-size:1rem;transition:var(--transition);}
.theme-toggle:hover{border-color:var(--neon);color:var(--neon);box-shadow:var(--glow);}

/* Hamburger */
.hamburger{display:none;flex-direction:column;gap:5px;cursor:pointer;padding:4px;}
.hamburger span{display:block;width:22px;height:2px;background:var(--neon);border-radius:2px;transition:var(--transition);}
.hamburger.open span:nth-child(1){transform:rotate(45deg) translate(5px,5px);}
.hamburger.open span:nth-child(2){opacity:0;}
.hamburger.open span:nth-child(3){transform:rotate(-45deg) translate(5px,-5px);}

/* Mobile Nav */
.mobile-nav{display:none;position:fixed;top:62px;left:0;right:0;background:rgba(2,12,14,0.97);backdrop-filter:blur(14px);border-bottom:1px solid var(--border);z-index:999;padding:20px 5%;flex-direction:column;gap:0;}
[data-theme="light"] .mobile-nav{background:rgba(240,244,245,0.97);}
.mobile-nav.open{display:flex;}
.mobile-nav a{font-family:'Share Tech Mono',monospace;font-size:0.85rem;color:var(--text-dim);text-decoration:none;letter-spacing:2px;padding:14px 0;border-bottom:1px solid var(--border);text-transform:uppercase;transition:color 0.2s;}
.mobile-nav a:hover{color:var(--neon);}

/* ===================== STATUS BAR ===================== */
.status-bar{position:fixed;bottom:0;width:100%;z-index:999;padding:5px 5%;background:rgba(2,12,14,0.9);border-top:1px solid var(--border);font-family:'Share Tech Mono',monospace;font-size:0.65rem;color:rgba(0,255,157,0.45);display:flex;gap:2rem;align-items:center;transition:background 0.4s;flex-wrap:wrap;}
[data-theme="light"] .status-bar{background:rgba(240,244,245,0.95);color:rgba(0,122,77,0.6);}
.status-dot{width:5px;height:5px;border-radius:50%;background:var(--neon);box-shadow:var(--glow);animation:blink 1.5s infinite;flex-shrink:0;display:inline-block;vertical-align:middle;margin-right:5px;}

/* ===================== SECTIONS ===================== */
section{position:relative;z-index:1;padding:100px 8%;}
.section-header{margin-bottom:55px;display:flex;align-items:center;gap:16px;}
.section-num{font-family:'Orbitron',monospace;font-size:0.65rem;color:var(--neon);opacity:0.5;letter-spacing:3px;white-space:nowrap;}
.section-title{font-family:'Orbitron',monospace;font-size:clamp(1.4rem,3vw,2rem);font-weight:900;color:var(--white);letter-spacing:2px;white-space:nowrap;}
.section-line{flex:1;height:1px;background:linear-gradient(90deg,var(--border),transparent);min-width:20px;}

/* ===================== HERO ===================== */
#hero{min-height:100vh;display:flex;align-items:center;padding:80px 8% 80px;}
.grid-deco{position:absolute;inset:0;background-image:linear-gradient(var(--border) 1px,transparent 1px),linear-gradient(90deg,var(--border) 1px,transparent 1px);background-size:60px 60px;pointer-events:none;opacity:0.4;}
.hero-content{max-width:680px;}
.hero-tag{font-family:'Share Tech Mono',monospace;font-size:0.75rem;color:var(--neon);letter-spacing:4px;margin-bottom:1.4rem;opacity:0;animation:fadeUp 0.8s 0.5s forwards;}
.hero-tag::before{content:'[ ';}.hero-tag::after{content:' ]';}
.hero-name{font-family:'Orbitron',monospace;font-size:clamp(2.5rem,6vw,5rem);font-weight:900;line-height:1;color:var(--white);margin-bottom:0.6rem;opacity:0;animation:fadeUp 0.8s 0.7s forwards;position:relative;}
.hero-name .accent{color:var(--neon);text-shadow:var(--glow);}
.glitch-wrap{position:relative;display:inline-block;}
.glitch-wrap::before,.glitch-wrap::after{content:attr(data-text);position:absolute;top:0;left:0;font-family:'Orbitron',monospace;font-size:inherit;font-weight:inherit;pointer-events:none;}
.glitch-wrap::before{color:var(--red);animation:glitch 5s 3s infinite;opacity:0.6;}
.glitch-wrap::after{color:var(--neon2);animation:glitch 5s 3.2s infinite;opacity:0.4;}
.hero-role{font-family:'Share Tech Mono',monospace;font-size:1rem;color:var(--neon2);margin-bottom:1.4rem;min-height:1.5rem;opacity:0;animation:fadeUp 0.8s 0.9s forwards;}
.typing-cursor{display:inline-block;width:2px;height:1em;background:var(--neon2);margin-left:2px;vertical-align:middle;animation:blink 0.8s infinite;}
.hero-desc{font-size:0.95rem;line-height:1.8;color:var(--text-dim);max-width:500px;margin-bottom:2.4rem;opacity:0;animation:fadeUp 0.8s 1.1s forwards;}
.hero-btns{display:flex;gap:1rem;flex-wrap:wrap;opacity:0;animation:fadeUp 0.8s 1.3s forwards;}
.btn-primary{padding:12px 30px;background:var(--neon);color:#000;font-family:'Orbitron',monospace;font-size:0.7rem;font-weight:700;letter-spacing:2px;text-decoration:none;clip-path:polygon(8px 0%,100% 0%,calc(100% - 8px) 100%,0% 100%);transition:var(--transition);box-shadow:var(--glow);border:none;cursor:pointer;}
.btn-primary:hover{background:transparent;color:var(--neon);outline:1px solid var(--neon);box-shadow:0 0 30px rgba(0,255,157,0.5);}
.btn-secondary{padding:12px 30px;background:transparent;color:var(--neon2);font-family:'Orbitron',monospace;font-size:0.7rem;font-weight:700;letter-spacing:2px;text-decoration:none;border:1px solid var(--neon2);clip-path:polygon(8px 0%,100% 0%,calc(100% - 8px) 100%,0% 100%);transition:var(--transition);cursor:pointer;}
.btn-secondary:hover{background:rgba(0,207,255,0.1);box-shadow:var(--glow2);}
.hero-stats{position:absolute;right:8%;top:50%;transform:translateY(-50%);display:flex;flex-direction:column;gap:1.5rem;opacity:0;animation:fadeUp 0.8s 1.5s forwards;}
.stat-box{border:1px solid var(--border);padding:18px 22px;background:rgba(10,30,34,0.5);backdrop-filter:blur(8px);text-align:center;position:relative;overflow:hidden;transition:border-color 0.3s;}
[data-theme="light"] .stat-box{background:rgba(255,255,255,0.7);}
.stat-box::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,var(--neon),transparent);animation:scanh 2s linear infinite;}
.stat-box:hover{border-color:var(--neon);}
.stat-num{font-family:'Orbitron',monospace;font-size:1.8rem;font-weight:900;color:var(--neon);text-shadow:var(--glow);display:block;}
.stat-label{font-family:'Share Tech Mono',monospace;font-size:0.6rem;letter-spacing:2px;color:var(--text-dim);text-transform:uppercase;}

/* ===================== ABOUT ===================== */
#about{background:linear-gradient(180deg,transparent,rgba(0,255,157,0.015),transparent);}
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:50px;align-items:start;}
.terminal-window{background:var(--card);border:1px solid var(--border);border-radius:4px;overflow:hidden;transition:border-color 0.3s;}
.terminal-window:hover{border-color:var(--neon);}
.terminal-bar{padding:9px 14px;background:rgba(0,0,0,0.35);display:flex;align-items:center;gap:7px;border-bottom:1px solid var(--border);}
[data-theme="light"] .terminal-bar{background:rgba(0,0,0,0.07);}
.t-dot{width:10px;height:10px;border-radius:50%;}
.t-dot.red{background:#ff2d55;}.t-dot.yellow{background:#ffd60a;}.t-dot.green{background:#30d158;}
.terminal-title{font-family:'Share Tech Mono',monospace;font-size:0.65rem;color:var(--text-dim);margin-left:8px;letter-spacing:1px;}
.terminal-body{padding:22px;font-family:'Share Tech Mono',monospace;font-size:0.78rem;line-height:2;color:var(--text);}
.t-prompt{color:var(--neon);}.t-cmd{color:var(--neon2);}.t-out{color:var(--text-dim);padding-left:14px;display:block;}
.t-key{color:var(--red);}.t-val{color:var(--white);}
.about-text p{line-height:1.85;color:var(--text-dim);margin-bottom:1.1rem;font-size:0.95rem;}
.about-tags{display:flex;flex-wrap:wrap;gap:8px;margin-top:1.4rem;}
.tag{padding:5px 13px;font-family:'Share Tech Mono',monospace;font-size:0.68rem;border:1px solid var(--border);color:var(--neon);letter-spacing:1px;background:rgba(0,255,157,0.04);clip-path:polygon(5px 0%,100% 0%,calc(100% - 5px) 100%,0% 100%);transition:var(--transition);}
.tag:hover{background:rgba(0,255,157,0.1);border-color:var(--neon);}

/* ===================== SKILLS ===================== */
#skills{background:var(--bg2);}
.skills-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;}
.skill-card{background:var(--card);border:1px solid var(--border);padding:24px;position:relative;overflow:hidden;transition:var(--transition);cursor:default;}
.skill-card::after{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,var(--neon),var(--neon2));transform:scaleX(0);transition:transform 0.35s;transform-origin:left;}
.skill-card:hover{border-color:var(--neon);transform:translateY(-5px);box-shadow:0 10px 40px rgba(0,0,0,0.3);}
.skill-card:hover::after{transform:scaleX(1);}
.skill-icon{font-size:1.6rem;margin-bottom:10px;display:block;}
.skill-name{font-family:'Orbitron',monospace;font-size:0.72rem;font-weight:700;color:var(--white);letter-spacing:1px;margin-bottom:12px;}
.skill-bar-wrap{height:3px;background:rgba(0,255,157,0.1);position:relative;overflow:hidden;}
.skill-bar{height:100%;background:linear-gradient(90deg,var(--neon),var(--neon2));box-shadow:0 0 8px rgba(0,255,157,0.5);transition:width 1.5s cubic-bezier(0.4,0,0.2,1);width:0%;}
.skill-items{margin-top:10px;display:flex;flex-wrap:wrap;gap:4px;}
.skill-pill{font-family:'Share Tech Mono',monospace;font-size:0.62rem;color:var(--text-dim);border:1px solid rgba(0,255,157,0.12);padding:2px 7px;}

/* ===================== PROJECTS ===================== */
#projects{background:linear-gradient(180deg,transparent,rgba(0,207,255,0.015),transparent);}
.projects-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px;}
.project-card{background:var(--card);border:1px solid var(--border);overflow:hidden;position:relative;transition:var(--transition);}
.project-card:hover{border-color:rgba(0,207,255,0.45);transform:translateY(-6px);box-shadow:0 12px 40px rgba(0,0,0,0.3);}
.project-card:hover .project-overlay{opacity:1;}
.project-card:hover .project-links{transform:translateY(0);opacity:1;}
.project-header{padding:22px 22px 14px;display:flex;justify-content:space-between;align-items:center;}
.project-type{font-family:'Share Tech Mono',monospace;font-size:0.62rem;color:var(--neon);letter-spacing:2px;background:rgba(0,255,157,0.08);border:1px solid rgba(0,255,157,0.2);padding:3px 9px;}
.project-status{font-family:'Share Tech Mono',monospace;font-size:0.62rem;display:flex;align-items:center;gap:5px;color:var(--text-dim);}
.pulse-dot{width:6px;height:6px;background:var(--neon);border-radius:50%;box-shadow:0 0 8px var(--neon);animation:blink 1s infinite;}
.project-body{padding:0 22px 22px;}
.project-title{font-family:'Orbitron',monospace;font-size:0.95rem;font-weight:700;color:var(--white);margin-bottom:9px;letter-spacing:1px;}
.project-desc{font-size:0.85rem;color:var(--text-dim);line-height:1.7;margin-bottom:16px;}
.project-tech{display:flex;flex-wrap:wrap;gap:5px;}
.tech-tag{font-family:'Share Tech Mono',monospace;font-size:0.62rem;color:var(--neon2);border:1px solid rgba(0,207,255,0.2);padding:2px 8px;background:rgba(0,207,255,0.05);}
.project-overlay{position:absolute;inset:0;background:rgba(0,10,12,0.75);opacity:0;transition:opacity 0.3s;display:flex;align-items:center;justify-content:center;}
.project-links{display:flex;gap:14px;transform:translateY(16px);opacity:0;transition:var(--transition);}
.proj-link{padding:9px 22px;font-family:'Share Tech Mono',monospace;font-size:0.72rem;text-decoration:none;letter-spacing:1px;transition:var(--transition);}
.proj-link.primary{background:var(--neon);color:#000;font-weight:700;}
.proj-link.primary:hover{box-shadow:var(--glow);}
.proj-link.secondary{border:1px solid var(--neon2);color:var(--neon2);}
.proj-link.secondary:hover{background:rgba(0,207,255,0.1);}

/* ===================== CONTACT ===================== */
#contact{background:var(--bg2);}
.contact-wrap{display:grid;grid-template-columns:1fr 1fr;gap:50px;align-items:start;}
.contact-info h3{font-family:'Orbitron',monospace;font-size:1rem;color:var(--white);margin-bottom:0.9rem;letter-spacing:1px;}
.contact-info p{color:var(--text-dim);line-height:1.85;margin-bottom:1.8rem;font-size:0.9rem;}
.contact-items{display:flex;flex-direction:column;gap:12px;}
.contact-item{display:flex;align-items:center;gap:14px;padding:13px 18px;border:1px solid var(--border);background:var(--card);transition:var(--transition);}
.contact-item:hover{border-color:var(--neon);transform:translateX(4px);}
.c-icon{width:34px;height:34px;display:flex;align-items:center;justify-content:center;border:1px solid var(--neon);color:var(--neon);font-size:0.9rem;flex-shrink:0;}
.c-label{font-family:'Share Tech Mono',monospace;font-size:0.6rem;color:var(--text-dim);letter-spacing:2px;text-transform:uppercase;display:block;margin-bottom:2px;}
.c-val{font-size:0.88rem;color:var(--white);}
.c-val a{color:var(--white);text-decoration:none;}
.c-val a:hover{color:var(--neon);}
.contact-form{display:flex;flex-direction:column;gap:14px;}
.form-label{font-family:'Share Tech Mono',monospace;font-size:0.62rem;color:var(--neon);letter-spacing:2px;margin-bottom:5px;display:block;}
.form-input,.form-textarea{width:100%;background:var(--card);border:1px solid var(--border);color:var(--white);font-family:'Share Tech Mono',monospace;font-size:0.78rem;padding:11px 14px;outline:none;transition:var(--transition);resize:none;}
.form-input:focus,.form-textarea:focus{border-color:var(--neon);box-shadow:0 0 12px rgba(0,255,157,0.1);}
.form-textarea{height:110px;}
.form-submit{padding:13px 36px;background:linear-gradient(90deg,var(--neon),var(--neon2));border:none;color:#000;font-family:'Orbitron',monospace;font-size:0.7rem;font-weight:700;letter-spacing:3px;cursor:pointer;clip-path:polygon(10px 0%,100% 0%,calc(100% - 10px) 100%,0% 100%);transition:var(--transition);align-self:flex-start;}
.form-submit:hover{box-shadow:0 0 30px rgba(0,255,157,0.5);transform:translateX(4px);}

/* ===================== FOOTER ===================== */
footer{position:relative;z-index:1;padding:24px 8% 50px;border-top:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;background:rgba(2,12,14,0.9);flex-wrap:wrap;gap:10px;transition:background 0.4s;}
[data-theme="light"] footer{background:rgba(240,244,245,0.95);}
.footer-logo{font-family:'Orbitron',monospace;font-size:0.9rem;color:var(--neon);text-shadow:var(--glow);}
.footer-copy{font-family:'Share Tech Mono',monospace;font-size:0.65rem;color:var(--text-dim);letter-spacing:1px;}

/* ===================== SCROLL REVEAL ===================== */
.reveal{opacity:0;transform:translateY(28px);transition:opacity 0.7s cubic-bezier(0.4,0,0.2,1),transform 0.7s cubic-bezier(0.4,0,0.2,1);}
.reveal.visible{opacity:1;transform:translateY(0);}
.reveal-delay-1{transition-delay:0.1s;}
.reveal-delay-2{transition-delay:0.2s;}
.reveal-delay-3{transition-delay:0.3s;}

/* ===================== KEYFRAMES ===================== */
@keyframes fadeUp{from{opacity:0;transform:translateY(24px);}to{opacity:1;transform:translateY(0);}}
@keyframes blink{0%,100%{opacity:1;}50%{opacity:0;}}
@keyframes scanh{0%{transform:translateX(-100%);}100%{transform:translateX(100%);}}
@keyframes glitch{
  0%,85%,100%{clip-path:inset(0 0 100% 0);transform:translateX(0);}
  87%{clip-path:inset(20% 0 60% 0);transform:translateX(-4px);}
  89%{clip-path:inset(50% 0 30% 0);transform:translateX(4px);}
  91%{clip-path:inset(80% 0 5% 0);transform:translateX(-2px);}
  93%{clip-path:inset(0% 0 85% 0);transform:translateX(2px);}
}

/* ===================== RESPONSIVE ===================== */
@media (max-width:1100px){.hero-stats{display:none;}}
@media (max-width:900px){
  .nav-center{display:none;}
  .hamburger{display:flex;}
  .about-grid,.contact-wrap{grid-template-columns:1fr;}
  .skills-grid{grid-template-columns:repeat(2,1fr);}
  .projects-grid{grid-template-columns:1fr;}
}
@media (max-width:600px){
  .skills-grid{grid-template-columns:1fr;}
  section{padding:70px 5%;}
  nav{padding:0 4%;}
  .hero-btns{flex-direction:column;}
  .btn-primary,.btn-secondary{text-align:center;}
}
@media (max-width:360px){
  .hero-name{font-size:2rem;}
  .nav-logo{font-size:0.85rem;}
}

/* Hide default Blogger elements */
#blogger-section-wrapper{display:none!important;}

