const langMeta = {
  en:{ flag:'🇺🇸', label:'EN', dir:'ltr' },
  bn:{ flag:'🇧🇩', label:'BN', dir:'ltr' },
  ar:{ flag:'🇸🇦', label:'AR', dir:'rtl' },
  es:{ flag:'🇪🇸', label:'ES', dir:'ltr' },
  fr:{ flag:'🇫🇷', label:'FR', dir:'ltr' },
  hi:{ flag:'🇮🇳', label:'HI', dir:'ltr' }
};

let currentLang = 'en';

function setLang(lang) {
  currentLang = lang;
  const t = i18n[lang];
  const m = langMeta[lang];
  document.documentElement.lang = lang;
  document.documentElement.dir = m.dir;
  document.getElementById('lang-flag').textContent = m.flag;
  document.getElementById('lang-label').textContent = m.label;
  document.querySelectorAll('.lang-option').forEach(o => {
    o.classList.toggle('active', o.getAttribute('onclick').includes("'" + lang + "'"));
  });
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if(t[key] !== undefined) el.textContent = t[key];
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    if(t[key] !== undefined) el.placeholder = t[key];
  });
  typedRoles = t.typed_roles;
  roleIdx = 0; charIdx = 0; isDeleting = false;
  document.getElementById('lang-wrap').classList.remove('open');
}

function toggleLang() {
  document.getElementById('lang-wrap').classList.toggle('open');
}

document.addEventListener('click', e => {
  if(!document.getElementById('lang-wrap').contains(e.target)) {
    document.getElementById('lang-wrap').classList.remove('open');
  }
});

// ===================== THEME =====================
function toggleTheme() {
  const html = document.documentElement;
  const isDark = html.getAttribute('data-theme') === 'dark';
  html.setAttribute('data-theme', isDark ? 'light' : 'dark');
  document.getElementById('theme-btn').textContent = isDark ? '🌙' : '☀️';
  updateNetworkColors();
}

// ===================== MOBILE NAV =====================
function toggleMobileNav() {
  document.getElementById('mobile-nav').classList.toggle('open');
  document.getElementById('hamburger').classList.toggle('open');
}

// ===================== LOADING SCREEN =====================
const loaderLines = [
  { text: '$ sudo ./initialize_portfolio.sh', cls:'cmd', delay:0 },
  { text: '[OK] Establishing encrypted connection...', cls:'ok', delay:400 },
  { text: '[OK] Loading security modules...', cls:'ok', delay:800 },
  { text: '[WARN] Detecting external probes...', cls:'warn', delay:1200 },
  { text: '[OK] Firewall rules applied (iptables)', cls:'ok', delay:1600 },
  { text: '[OK] Decrypting portfolio data...', cls:'ok', delay:2000 },
  { text: '[OK] Rendering interface v2.0...', cls:'ok', delay:2400 },
  { text: '[OK] All systems operational. Welcome.', cls:'ok', delay:2800 },
];

function runLoader() {
  const container = document.getElementById('loader-lines');
  const bar = document.getElementById('loader-bar');
  const pct = document.getElementById('loader-pct');
  loaderLines.forEach((l, i) => {
    setTimeout(() => {
      const span = document.createElement('div');
      span.className = 'loader-line show';
      span.innerHTML = '<span class="' + l.cls + '">' + l.text + '</span>';
      container.appendChild(span);
      const p = Math.round(((i+1)/loaderLines.length)*100);
      bar.style.width = p + '%';
      pct.textContent = p + '%';
    }, l.delay);
  });
  setTimeout(() => {
    document.getElementById('loader').classList.add('hidden');
    animateCounters();
  }, 3400);
}
runLoader();

// ===================== NETWORK PARTICLE BG =====================
const canvas = document.getElementById('net-canvas');
const ctx = canvas.getContext('2d');
let W, H, nodes = [], animId;
const NODE_COUNT = 65;
let netColor = '#00ff9d';

function updateNetworkColors() {
  netColor = document.documentElement.getAttribute('data-theme')==='light' ? '#007a4d' : '#00ff9d';
}

function resize() {
  W = canvas.width = window.innerWidth;
  H = canvas.height = window.innerHeight;
}
resize();
window.addEventListener('resize', () => { resize(); initNodes(); });

class Node {
  constructor() { this.reset(); }
  reset() {
    this.x = Math.random()*W;
    this.y = Math.random()*H;
    this.vx = (Math.random()-0.5)*0.4;
    this.vy = (Math.random()-0.5)*0.4;
    this.r = Math.random()*2+1;
    this.pulse = Math.random()*Math.PI*2;
  }
  update() {
    this.x += this.vx; this.y += this.vy;
    this.pulse += 0.025;
    if(this.x<-10||this.x>W+10||this.y<-10||this.y>H+10) this.reset();
  }
}

function initNodes() {
  nodes = Array.from({length:NODE_COUNT}, ()=>new Node());
}
initNodes();

let mouseX=-9999, mouseY=-9999;
document.addEventListener('mousemove', e=>{ mouseX=e.clientX; mouseY=e.clientY; });

function drawNet() {
  ctx.clearRect(0,0,W,H);
  const nc = netColor;
  nodes.forEach(n => n.update());
  for(let i=0;i<nodes.length;i++){
    for(let j=i+1;j<nodes.length;j++){
      const dx=nodes[i].x-nodes[j].x, dy=nodes[i].y-nodes[j].y;
      const d=Math.sqrt(dx*dx+dy*dy);
      if(d<140){
        ctx.beginPath();
        ctx.strokeStyle=nc;
        ctx.globalAlpha=(1-d/140)*0.35;
        ctx.lineWidth=0.5;
        ctx.moveTo(nodes[i].x,nodes[i].y);
        ctx.lineTo(nodes[j].x,nodes[j].y);
        ctx.stroke();
      }
    }
    const mdx=nodes[i].x-mouseX, mdy=nodes[i].y-mouseY;
    const md=Math.sqrt(mdx*mdx+mdy*mdy);
    if(md<180){
      ctx.beginPath();
      ctx.strokeStyle=nc;
      ctx.globalAlpha=(1-md/180)*0.6;
      ctx.lineWidth=0.8;
      ctx.moveTo(nodes[i].x,nodes[i].y);
      ctx.lineTo(mouseX,mouseY);
      ctx.stroke();
    }
  }
  nodes.forEach(n=>{
    const ps=0.5+Math.sin(n.pulse)*0.5;
    ctx.beginPath();
    ctx.arc(n.x,n.y,n.r,0,Math.PI*2);
    ctx.fillStyle=nc;
    ctx.globalAlpha=0.6+ps*0.3;
    ctx.fill();
    ctx.beginPath();
    ctx.arc(n.x,n.y,n.r+2+ps*2,0,Math.PI*2);
    ctx.strokeStyle=nc;
    ctx.globalAlpha=0.08+ps*0.06;
    ctx.lineWidth=1;
    ctx.stroke();
  });
  ctx.globalAlpha=1;
  animId = requestAnimationFrame(drawNet);
}
drawNet();

// ===================== TYPING EFFECT =====================
let typedRoles = i18n.en.typed_roles;
let roleIdx=0, charIdx=0, isDeleting=false;

function typeWriter() {
  const cur = typedRoles[roleIdx];
  const el = document.getElementById('typed-role');
  if(!el) return;
  if(!isDeleting) {
    el.textContent = cur.slice(0,++charIdx);
    if(charIdx===cur.length){ isDeleting=true; setTimeout(typeWriter,1800); return; }
  } else {
    el.textContent = cur.slice(0,--charIdx);
    if(charIdx===0){ isDeleting=false; roleIdx=(roleIdx+1)%typedRoles.length; }
  }
  setTimeout(typeWriter, isDeleting?40:75);
}
typeWriter();

// ===================== CLOCK =====================
function updateClock() {
  const n=new Date();
  document.getElementById('clock-bar').textContent=
    'SYS: ' + n.toLocaleTimeString('en-GB') + ' | ' + n.toLocaleDateString('en-GB');
}
setInterval(updateClock,1000); updateClock();

// ===================== COUNTER ANIMATION =====================
function animateCounter(el,target) {
  let cur=0; const step=Math.ceil(target/55);
  const iv=setInterval(()=>{
    cur=Math.min(cur+step,target);
    el.textContent=cur+'+';
    if(cur>=target) clearInterval(iv);
  },28);
}
function animateCounters() {
  document.querySelectorAll('[data-count]').forEach(el=>{
    animateCounter(el,parseInt(el.dataset.count));
  });
}

// ===================== SCROLL REVEAL =====================
const revObs = new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      e.target.classList.add('visible');
      if(e.target.closest('#skills')){
        document.querySelectorAll('.skill-bar').forEach(b=>{ b.style.width=b.dataset.width; });
      }
    }
  });
},{threshold:0.12});
document.querySelectorAll('.reveal').forEach(el=>revObs.observe(el));

