  this.textContent = currentLang==='bn'?'পাঠানো হয়েছে ✓':currentLang==='ar'?'تم الإرسال ✓':'SENT ✓';
  this.style.background='linear-gradient(90deg,#00ff9d,#00cfff)';
  this.style.boxShadow='0 0 30px rgba(0,255,157,0.5)';
  setTimeout(()=>{
    this.textContent = i18n[currentLang].form_send;
    this.style.background='';
    this.style.boxShadow='';
  },3000);
});
